const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;
  const input = raw.body || raw;

  const required = ['issue_id', 'user_id', 'location'];
  const missing = required.filter(field => !input[field]);

  if (missing.length > 0) {
    throw new Error(`Missing required fields: ${missing.join(', ')}. Received keys: ${Object.keys(input).join(', ')}`);
  }

  if (!input.image_url && !input.image_base64) {
    throw new Error('Either image_url or image_base64 is required');
  }

  if (!input.location?.latitude || !input.location?.longitude) {
    throw new Error('Location must include latitude and longitude');
  }

  results.push({
    json: {
      issue_id: input.issue_id,
      user_id: input.user_id,
      image_url: input.image_url || null,
      image_base64: input.image_base64 || null,
      image_mime: input.image_mime || 'image/jpeg',
      needs_image_fetch: !!(input.image_url && !input.image_base64),
      location: {
        latitude: parseFloat(input.location.latitude),
        longitude: parseFloat(input.location.longitude),
        address: input.location.address || 'Unknown'
      },
      description: input.description || '',
      timestamp: input.timestamp || new Date().toISOString(),
      validated_at: new Date().toISOString()
    }
  });
}

return results;

const items = $input.all();
const originalData = $('Validate Input').first().json;
const results = [];

for (const item of items) {
  let imageBase64 = originalData.image_base64;
  let imageMime = originalData.image_mime || 'image/jpeg';

  if (item.binary && item.binary.data) {
    const binaryBuffer = await this.helpers.getBinaryDataBuffer(item.index ?? 0, 'data');
    imageBase64 = binaryBuffer.toString('base64');
    imageMime = item.binary.data.mimeType || 'image/jpeg';
  }

  results.push({
    json: {
      ...originalData,
      image_base64: imageBase64,
      image_mime: imageMime,
      needs_image_fetch: false
    }
  });
}

return results;

const items = $input.all();
const results = [];

const systemPrompt = `You are an environmental issue analyzer for a city reporting app. Analyze the image and provide a structured assessment.

Your Task: Identify the problem, classify severity, suggest who should handle it.

Severity Levels:
- EASY: Small litter, minor graffiti, overgrown grass, small broken items, faded signs
- MEDIUM: Large trash piles, broken public furniture, potholes under 20cm, damaged fencing, blocked drains, small dead animals, vandalism
- HIGH: Fallen trees blocking roads, large potholes (safety hazard), exposed wires, gas leaks, flooding, structural damage, hazardous waste, immediate danger

Categories: trash, road_damage, vegetation, vandalism, utilities, infrastructure, safety_hazard, pollution, animal, other

Authority Types: sanitation, roads_department, parks_department, utilities_electric, utilities_water, utilities_gas, police, emergency_services, animal_control, environmental

Respond in JSON:
{"severity":"EASY|MEDIUM|HIGH","category":"category","problem_detected":true,"description":"description","specific_issue":"type","confidence":0.0-1.0,"authority_type":"authority","safety_concern":false,"estimated_effort":"effort","recommended_action":"action","notes":"notes"}

If no problem: {"severity":null,"problem_detected":false,"description":"No issue detected","notes":"what image shows"}`;

for (const item of items) {
  const data = item.json;

  results.push({
    json: {
      ...data,
      ai_request_body: {
        contents: [{
          role: 'user',
          parts: [
            { text: systemPrompt + '\n\nAnalyze this image. Location: ' + data.location.address + '. User description: ' + data.description },
            { inline_data: { mime_type: data.image_mime || 'image/jpeg', data: data.image_base64 } }
          ]
        }],
        generationConfig: {
          responseMimeType: 'application/json',
          maxOutputTokens: 900,
          temperature: 0.2
        }
      }
    }
  });
}

return results;

const items = $input.all();
const originalData = $('Prepare AI Request').first().json;
const results = [];

for (const item of items) {
  const aiResponse = item.json;
  const content = aiResponse.candidates?.[0]?.content?.parts?.[0]?.text
    || aiResponse.choices?.[0]?.message?.content;

  let aiResult;
  try {
    aiResult = JSON.parse(content);
  } catch (e) {
    aiResult = {
      severity: 'MEDIUM',
      problem_detected: true,
      description: content || 'Unable to parse AI response',
      confidence: 0.5,
      notes: 'Failed to parse structured response'
    };
  }

  const validSeverities = ['EASY', 'MEDIUM', 'HIGH'];
  if (!validSeverities.includes(aiResult.severity)) {
    aiResult.severity = 'MEDIUM';
  }

  const priorityScores = { EASY: 10, MEDIUM: 50, HIGH: 100 };

  results.push({
    json: {
      ...originalData,
      ai_result: aiResult,
      priority_score: priorityScores[aiResult.severity],
      processed_by_ai: true,
      ai_processed_at: new Date().toISOString()
    }
  });
}

return results;

