      department: 'General Inquiries',
      email: 'info@' + (lookupData.geocode_city || 'city').toLowerCase().replace(/\s+/g, '') + '.de',
      confidence: 0.2,
      notes: 'AI lookup failed, using fallback'
    };
  }

  const address = lookupData.geocode_address || highData.location.address;
  const city = lookupData.geocode_city || 'Unknown';
