  const execution = error.execution || {};
  const lastNode = execution.lastNodeExecuted || 'unknown';

  return {
    json: {
      success: false,
      error: error.message || error.error?.message || 'Unknown processing error',
      failed_node: lastNode,
      code: 'PROCESSING_ERROR',
